package main
import("container/heap";"encoding/json";"flag";"math";"os")
type E struct{From int `json:"from"`;To int `json:"to"`;Weight int64 `json:"weight"`};type Q struct{ID int `json:"id"`;Source int `json:"source"`;Destination int `json:"destination"`};type G struct{N int `json:"vertexCount"`;Edges []E `json:"edges"`;Queries []Q `json:"queries"`};type R struct{ID int `json:"queryId"`;Distance *int64 `json:"distance"`;Path []int `json:"path"`};type I struct{n int;d int64};type P []I
func(p P)Len()int{return len(p)};func(p P)Less(i,j int)bool{return p[i].d<p[j].d};func(p P)Swap(i,j int){p[i],p[j]=p[j],p[i]};func(p *P)Push(x any){*p=append(*p,x.(I))};func(p *P)Pop()any{o:=*p;x:=o[len(o)-1];*p=o[:len(o)-1];return x}
func main(){in:=flag.String("input","","");out:=flag.String("output","","");flag.Parse();b,_:=os.ReadFile(*in);var g G;json.Unmarshal(b,&g);a:=make([][]E,g.N);for _,e:=range g.Edges{a[e.From]=append(a[e.From],e)};rs:=[]R{};for _,q:=range g.Queries{d:=make([]int64,g.N);pr:=make([]int,g.N);for i:=range d{d[i]=math.MaxInt64;pr[i]=-1};d[q.Source]=0;p:=&P{{q.Source,0}};heap.Init(p);for p.Len()>0{x:=heap.Pop(p).(I);if x.d!=d[x.n]{continue};for _,e:=range a[x.n]{nd:=x.d+e.Weight;if nd<d[e.To]{d[e.To]=nd;pr[e.To]=x.n;heap.Push(p,I{e.To,nd})}}};if d[q.Destination]==math.MaxInt64{rs=append(rs,R{q.ID,nil,[]int{}})}else{pa:=[]int{};for x:=q.Destination;x>=0;x=pr[x]{pa=append(pa,x)};for i,j:=0,len(pa)-1;i<j;i,j=i+1,j-1{pa[i],pa[j]=pa[j],pa[i]};v:=d[q.Destination];rs=append(rs,R{q.ID,&v,pa})}};b,_=json.Marshal(struct{Benchmark string `json:"benchmark"`;Version int `json:"version"`;Results []R `json:"results"`}{"shortest-path",1,rs});os.WriteFile(*out,b,0644)}
